<?php\n\nnamespace FederatedJsonStore\\Storage;\n\nuse FederatedJsonStore\\Exception\\NodeConnectionException;\nuse FederatedJsonStore\\Exception\\DocumentNotFoundException;\nuse GuzzleHttp\\Client as HttpClient;\nuse GuzzleHttp\\Exception\\GuzzleException;\n\n/**\n * NodeClient handles communication with a single federated JSON store node.\n * It provides methods for CRUD operations and query execution against a remote node.\n */\nclass NodeClient\n{\n    private HttpClient $httpClient;\n    private string $nodeBaseUrl;\n\n    /**\n     * NodeClient constructor.\n     *\n     * @param string $nodeBaseUrl The base URL of the remote JSON store node.\n     * @param array $config Optional Guzzle HTTP client configuration.\n     */\n    public function __construct(string $nodeBaseUrl, array $config = [])\n    {\n        $this->nodeBaseUrl = rtrim($nodeBaseUrl, '/');\n        $this->httpClient = new HttpClient(array_merge([\n            'base_uri' => $this->nodeBaseUrl,\n            'timeout' => 10.0,\n            'headers' => [\n                'Content-Type' => 'application/json',\n                'Accept' => 'application/json',\n            ],\n        ], $config));\n    }\n\n    /**\n     * Retrieves a document by its ID from the federated node.\n     *\n     * @param string $documentId The unique identifier of the document.\n     * @return array The document data.\n     * @throws DocumentNotFoundException If the document does not exist on the node.\n     * @throws NodeConnectionException On network or API errors during retrieval.\n     */\n    public function getDocument(string $documentId): array\n    {\n        try {\n            $response = $this->httpClient->get("/documents/{$documentId}");\n            $data = json_decode($response->getBody()->getContents(), true);\n            if (json_last_error() !== JSON_ERROR_NONE) {\n                throw new NodeConnectionException("Failed to decode JSON response from node: " . json_last_error_msg());\n            }\n            return $data;\n        } catch (GuzzleException $e) {\n            if ($e->getCode() === 404) {\n                throw new DocumentNotFoundException("Document '{$documentId}' not found on node '{$this->nodeBaseUrl}'.", 0, $e);\n            }\n            throw new NodeConnectionException("Failed to retrieve document '{$documentId}' from node '{$this->nodeBaseUrl}': " . $e->getMessage(), 0, $e);\n        }\n    }\n\n    /**\n     * Stores or updates a document on the federated node.\n     *\n     * @param string $documentId The unique identifier of the document.\n     * @param array $documentData The data to store.\n     * @return array The response from the node, typically containing the stored document's metadata.\n     * @throws NodeConnectionException On network or API errors during storage.\n     */\n    public function putDocument(string $documentId, array $documentData): array\n    {\n        try {\n            $response = $this->httpClient->put("/documents/{$documentId}", [\n                'json' => $documentData,\n            ]);\n            $data = json_decode($response->getBody()->getContents(), true);\n            if (json_last_error() !== JSON_ERROR_NONE) {\n                throw new NodeConnectionException("Failed to decode JSON response from node: " . json_last_error_msg());\n            }\n            return $data;\n        } catch (GuzzleException $e) {\n            throw new NodeConnectionException("Failed to store document '{$documentId}' on node '{$this->nodeBaseUrl}': " . $e->getMessage(), 0, $e);\n        }\n    }\n\n    /**\n     * Deletes a document from the federated node.\n     *\n     * @param string $documentId The unique identifier of the document to delete.\n     * @return bool True on successful deletion.\n     * @throws DocumentNotFoundException If the document does not exist for deletion.\n     * @throws NodeConnectionException On network or API errors during deletion.\n     */\n    public function deleteDocument(string $documentId): bool\n    {\n        try {\n            $response = $this->httpClient->delete("/documents/{$documentId}");\n            if ($response->getStatusCode() === 204) { // No Content for successful deletion\n                return true;\n            }\n            throw new NodeConnectionException("Unexpected status code '{$response->getStatusCode()}' during deletion of '{$documentId}'.");\n        } catch (GuzzleException $e) {\n            if ($e->getCode() === 404) {\n                throw new DocumentNotFoundException("Document '{$documentId}' not found for deletion on node '{$this->nodeBaseUrl}'.", 0, $e);\n            }\n            throw new NodeConnectionException("Failed to delete document '{$documentId}' from node '{$this->nodeBaseUrl}': " . $e->getMessage(), 0, $e);\n        }\n    }\n\n    /**\n     * Queries documents on the federated node using a specified query payload.\n     *\n     * @param array $queryPayload The query parameters, typically a JSON object.\n     * @return array An array of matching documents.\n     * @throws NodeConnectionException On network or API errors during query execution.\n     */\n    public function queryDocuments(array $queryPayload): array\n    {\n        try {\n            $response = $this->httpClient->post("/query", [\n                'json' => $queryPayload,\n            ]);\n            $data = json_decode($response->getBody()->getContents(), true);\n            if (json_last_error() !== JSON_ERROR_NONE) {\n                throw new NodeConnectionException("Failed to decode JSON response from query: " . json_last_error_msg());\n            }\n            return $data;\n        } catch (GuzzleException $e) {\n            throw new NodeConnectionException("Failed to query documents on node '{$this->nodeBaseUrl}': " . $e->getMessage(), 0, $e);\n        }\n    }\n}